#include <iostream>
#include <string>
#include <vector>
#include <utility>

class HeavyResource {
private:
    std::string name;
    int* data;
    int size;

public:
    // Constructor
    HeavyResource(std::string n, int s) : name(n), size(s) {
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = i;
        }
        std::cout << "HeavyResource '" << name << "' created (size: " << size << ")" << std::endl;
    }

    // Copy Constructor (expensive)
    HeavyResource(const HeavyResource& other) 
        : name(other.name + " (copy)"), size(other.size) {
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = other.data[i];
        }
        std::cout << "Copy of '" << other.name << "' (expensive!)" << std::endl;
    }

    // Move Constructor (cheap)
    HeavyResource(HeavyResource&& other) noexcept
        : name(std::move(other.name)), data(other.data), size(other.size) {
        other.data = nullptr;
        other.size = 0;
        std::cout << "Move of '" << name << "' (cheap!)" << std::endl;
    }

    // Copy Assignment (expensive)
    HeavyResource& operator=(const HeavyResource& other) {
        std::cout << "Copy assignment of '" << other.name << "' (expensive!)" << std::endl;
        if (this == &other) return *this;

        delete[] data;
        name = other.name + " (copy assigned)";
        size = other.size;
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = other.data[i];
        }
        return *this;
    }

    // Move Assignment (cheap)
    HeavyResource& operator=(HeavyResource&& other) noexcept {
        std::cout << "Move assignment of '" << other.name << "' (cheap!)" << std::endl;
        if (this == &other) return *this;

        delete[] data;
        name = std::move(other.name);
        data = other.data;
        size = other.size;
        other.data = nullptr;
        other.size = 0;
        return *this;
    }

    // Destructor
    ~HeavyResource() {
        delete[] data;
        std::cout << "HeavyResource '" << name << "' destroyed" << std::endl;
    }

    void display() const {
        std::cout << name << " (size: " << size << ")" << std::endl;
    }
};

// Function that takes by value (uses move if possible)
void processHeavyResource(HeavyResource res) {
    std::cout << "Processing: ";
    res.display();
}

int main() {
    std::cout << "=== Move Semantics ===" << std::endl;

    std::cout << "\n--- Without move (copy) ---" << std::endl;
    HeavyResource res1("Resource A", 10);
    HeavyResource res2 = res1;  // Copy (expensive)

    std::cout << "\n--- With move (cheap) ---" << std::endl;
    HeavyResource res3 = std::move(res1);  // Move (cheap)
    std::cout << "After move, res1 is empty: ";
    res1.display();
    std::cout << "res3: ";
    res3.display();

    std::cout << "\n--- Move assignment ---" << std::endl;
    HeavyResource res4("Resource D", 5);
    res4 = std::move(res3);  // Move assignment
    std::cout << "After move, res3 is empty: ";
    res3.display();
    std::cout << "res4: ";
    res4.display();

    std::cout << "\n--- Passing by value with move ---" << std::endl;
    HeavyResource res5("Resource E", 8);
    processHeavyResource(std::move(res5));  // Move into function
    std::cout << "After function, res5 is empty: ";
    res5.display();

    std::cout << "\n--- std::move with vector ---" << std::endl;
    std::vector<HeavyResource> vec;
    vec.push_back(HeavyResource("Vec Resource", 3));  // Move into vector

    std::cout << "\n--- When to use move ---" << std::endl;
    std::cout << "Use std::move when:" << std::endl;
    std::cout << "  • You're done with the object" << std::endl;
    std::cout << "  • The object is expensive to copy" << std::endl;
    std::cout << "  • You want to transfer ownership" << std::endl;

    return 0;
}

