#include <iostream>
#include <string>
#include <vector>
#include <utility>

class LargeBuffer {
private:
    std::string name;
    int* data;
    int size;

public:
    LargeBuffer(std::string n, int s) : name(n), size(s) {
        data = new int[size];
        for (int i = 0; i < size; i++) data[i] = i;
        std::cout << "LargeBuffer '" << name << "' created (size: " << size << ")" << std::endl;
    }

    ~LargeBuffer() {
        delete[] data;
        std::cout << "LargeBuffer '" << name << "' destroyed" << std::endl;
    }

    LargeBuffer(const LargeBuffer& other) : name(other.name + " (copy)"), size(other.size) {
        data = new int[size];
        for (int i = 0; i < size; i++) data[i] = other.data[i];
        std::cout << "Copying LargeBuffer '" << other.name << "' (expensive!)" << std::endl;
    }

    LargeBuffer(LargeBuffer&& other) noexcept 
        : name(std::move(other.name)), data(other.data), size(other.size) {
        other.data = nullptr;
        other.size = 0;
        std::cout << "Moving LargeBuffer '" << name << "' (cheap!)" << std::endl;
    }

    void display() const {
        std::cout << name << " (size: " << size << ")" << std::endl;
    }
};

int main() {
    LargeBuffer buf1("Buffer A", 100);

    LargeBuffer buf2 = buf1;  // Copy

    LargeBuffer buf3 = std::move(buf1);  // Move

    std::vector<LargeBuffer> vec;
    vec.push_back(std::move(buf3));  // Move into vector

    std::cout << "\nAfter moves:" << std::endl;
    std::cout << "buf1: "; buf1.display();
    std::cout << "buf2: "; buf2.display();

    return 0;
}
